function stopRent(RentalOrder calldata order) external {
    _validateRentalCanBeStoped(order.orderType, order.endTimestamp, order.lender);
    bytes memory rentalAssetUpdates = new bytes(0);
    for (uint256 i; i < order.items.length; ++i) {
        if (order.items[i].isRental()) {
            _insert(rentalAssetUpdates, order.items[i].toRentalId(order.rentalWallet), order.items[i].amount);
        }
    }
    if (order.hooks.length > 0) {
        _removeHooks(order.hooks, order.items, order.rentalWallet); // EXTERNAL CALL 1
    }
    _reclaimRentedItems(order); // EXTERNAL CALL 2 - NFT transfer with callback
    ESCRW.settlePayment(order); // EXTERNAL CALL 3 - payment settlement
    STORE.removeRentals(_deriveRentalOrderHash(order), _convertToStatic(rentalAssetUpdates)); // STATE CLEANUP - too late
}

function stopRentBatch(RentalOrder[] calldata orders) external {
    bytes32[] memory orderHashes = new bytes32[](orders.length);
    bytes memory rentalAssetUpdates = new bytes(0);
    for (uint256 i = 0; i < orders.length; ++i) {
        _validateRentalCanBeStoped(...);
        // build updates...
        orderHashes[i] = _deriveRentalOrderHash(orders[i]);
        if (orders[i].hooks.length > 0) { _removeHooks(...); }
        _reclaimRentedItems(orders[i]); // callback here, no settlements/removals yet
        _emitRentalOrderStopped(orderHashes[i], msg.sender);
    }
    ESCRW.settlePaymentBatch(orders); // ALL settlements after ALL reclaims
    STORE.removeRentalsBatch(orderHashes, _convertToStatic(rentalAssetUpdates)); // ALL removals last
}

function _reclaimRentedItems(RentalOrder memory order) internal {
    bool success = ISafe(order.rentalWallet).execTransactionFromModule(
        address(this),
        0,
        abi.encodeWithSelector(this.reclaimRentalOrder.selector, order),
        Enum.Operation.DelegateCall
    );
    if (!success) {
        revert Errors.StopPolicy_ReclaimFailed();
    }
}

function reclaimRentalOrder(RentalOrder calldata rentalOrder) external {
    if (address(this) == original) { revert ...; }
    if (address(this) != rentalOrder.rentalWallet) { revert ...; }
    uint256 itemCount = rentalOrder.items.length;
    for (uint256 i = 0; i < itemCount; ++i) {
        Item memory item = rentalOrder.items[i];
        if (item.itemType == ItemType.ERC721)
            _transferERC721(item, rentalOrder.lender); // safeTransferFrom -> onERC721Received callback
        if (item.itemType == ItemType.ERC1155)
            _transferERC1155(item, rentalOrder.lender); // safeTransferFrom -> onERC1155Received callback
    }
}
